     1→{
     2→  inputs,
     3→  username,
     4→  ...
     5→}:
     6→let
     7→  system = "x86_64-linux";
     8→  nixpkgsConfig = import ../../lib/nixpkgs-config.nix {
     9→    nixpkgsLib = inputs.nixpkgs.lib;
    10→  };
    11→  overlays = import ../../overlays { inherit inputs; };
    12→  pkgs = import inputs.nixpkgs {
    13→    inherit system overlays;
    14→    config = nixpkgsConfig;
    15→  };
    16→
    17→  # Check if falcon .deb exists (for conditional import)
    18→  # In CI, this will be false; locally with .deb present, it will be true
    19→  falconDebExists = builtins.pathExists /etc/nixos/falcon-sensor.deb;
    20→in
    21→inputs.nixpkgs.lib.nixosSystem {
    22→  inherit system;
    23→  specialArgs = {
    24→    inherit inputs username;
    25→  };
    26→  modules = [
    27→    # Framework 13" AMD AI 300 hardware support
    28→    inputs.nixos-hardware.nixosModules.framework-amd-ai-300-series
    29→
    30→    # Hardware configuration
    31→    ./hardware-configuration.nix
    32→
    33→    # Kolide launcher
    34→    ./kolide.nix
    35→
    36→    # Base system configuration
    37→    (
    38→      { config, lib, ... }:
    39→      {
    40→        # Boot loader (EFI/systemd-boot)
    41→        boot.loader.systemd-boot.enable = true;
    42→        boot.loader.systemd-boot.configurationLimit = 10;
    43→        boot.loader.efi.canTouchEfiVariables = true;
    44→        boot.loader.timeout = 3;
    45→
    46→        # Pin kernel to 6.18 for CrowdStrike Falcon compatibility (RFM on 6.19)
    47→        boot.kernelPackages = pkgs.linuxPackages_6_18;
    48→
    49→        # Networking
    50→        networking.hostName = "matic";
    51→        networking.networkmanager.enable = true;
    52→        networking.networkmanager.wifi.powersave = false;
    53→
    54→        # Enable fish shell
    55→        programs.fish.enable = true;
    56→
    57→        # User configuration
    58→        users.users.${username} = {
    59→          isNormalUser = true;
    60→          extraGroups = [
    61→            "wheel"
    62→            "networkmanager"
    63→            "input"
    64→            "video"
    65→            "docker"
    66→          ];
    67→          home = "/home/${username}";
    68→          shell = pkgs.fish;
    69→          initialPassword = "changemeow"; # Change this after first login with: passwd
    70→        };
    71→
    72→        # Docker
    73→        virtualisation.docker.enable = true;
    74→
    75→        security.sudo.wheelNeedsPassword = false;
    76→
    77→        # Keyd configuration (Linux desktop only)
    78→        services.keyd.enable = true;
    79→        users.groups.keyd = { };
    80→        systemd.services.keyd.serviceConfig = {
    81→          CapabilityBoundingSet = [ "CAP_SETGID" ];
    82→          AmbientCapabilities = [ "CAP_SETGID" ];
    83→        };
    84→        systemd.services.keyd.restartTriggers = [
    85→          (builtins.hashFile "sha256" ../../config/keyd/default.conf)
    86→        ];
    87→        environment.etc."keyd/default.conf".source = ../../config/keyd/default.conf;
    88→
    89→        # Input remapping (xremap)
    90→        hardware.uinput.enable = true;
    91→        services.udev.extraRules = ''
    92→          KERNEL=="uinput", GROUP="input", TAG+="uaccess", MODE:="0660", OPTIONS+="static_node=uinput"
    93→          KERNEL=="event*", ATTRS{name}=="keyd virtual keyboard", GROUP="input", MODE:="0660"
    94→          KERNEL=="event*", ATTRS{name}=="keyd virtual pointer", GROUP="input", MODE:="0660"
    95→        '';
    96→
    97→        # AMD graphics with hardware acceleration
    98→        hardware.graphics.enable = true;
    99→        hardware.graphics.extraPackages = with pkgs; [
   100→          libva
   101→          libva-vdpau-driver
   102→          libvdpau-va-gl
   103→        ];
   104→
   105→        # Thunderbolt support
   106→        services.hardware.bolt.enable = true;
   107→
   108→        # Fingerprint authentication
   109→        services.fprintd.enable = true;
   110→
   111→        # Firmware updates
   112→        services.fwupd.enable = true;
   113→
   114→        # Power management
   115→        services.upower.enable = true;
   116→        services.power-profiles-daemon.enable = true;
   117→
   118→        # Power button behavior - lock screen instead of shutdown
   119→        services.logind.settings.Login.HandlePowerKey = "lock";
   120→
   121→        # Auto timezone (via geolocation)
   122→        services.geoclue2.enable = true;
   123→        services.localtimed.enable = true;
   124→
   125→        # Audio (PipeWire)
   126→        services.pipewire = {
   127→          enable = true;
   128→          alsa.enable = true;
   129→          alsa.support32Bit = true;
   130→          pulse.enable = true;
   131→          wireplumber.enable = true;
   132→        };
   133→        services.pulseaudio.enable = false;
   134→        security.rtkit.enable = true;
   135→
   136→        # Bluetooth
   137→        hardware.bluetooth.enable = true;
   138→        hardware.bluetooth.powerOnBoot = true;
   139→
   140→        # Login manager (greetd + tuigreet)
   141→        services.greetd = {
   142→          enable = true;
   143→          settings = {
   144→            default_session = {
   145→              command = "${pkgs.tuigreet}/bin/tuigreet --time --remember --remember-session --asterisks --sessions /etc/greetd/wayland-sessions";
   146→              user = "greeter";
   147→            };
   148→          };
   149→        };
   150→
   151→        # Provide Hyprland session file for tuigreet to discover
   152→        environment.etc."greetd/wayland-sessions/hyprland.desktop".text = ''
   153→          [Desktop Entry]
   154→          Name=Hyprland
   155→          Exec=uwsm start hyprland-uwsm.desktop
   156→          Type=Application
   157→        '';
   158→
   159→        programs.hyprland = {
   160→          enable = true;
   161→          package = pkgs.hyprland;
   162→          portalPackage = pkgs.xdg-desktop-portal-hyprland;
   163→          xwayland.enable = true;
   164→          withUWSM = true;
   165→        };
   166→
   167→        # Steam (for Wallpaper Engine assets)
   168→        programs.steam.enable = true;
   169→
   170→        programs.dconf.enable = true;
   171→
   172→        xdg.portal = {
   173→          enable = true;
   174→          extraPortals = with pkgs; [
   175→            xdg-desktop-portal-gtk
   176→          ];
   177→          config = {
   178→            hyprland = {
   179→              default = [
   180→                "hyprland"
   181→                "gtk"
   182→              ];
   183→              "org.freedesktop.impl.portal.Settings" = [ "gtk" ];
   184→            };
   185→          };
   186→        };
   187→
   188→        # WiFi MT7925e fix (disable ASPM)
   189→        boot.extraModprobeConfig = ''
   190→          options mt7925e disable_aspm=1
   191→        '';
   192→
   193→        # System packages
   194→        environment.systemPackages = with pkgs; [
   195→          curl
   196→          git
   197→          home-manager
   198→          vim
   199→          wget
   200→          zellij
   201→        ];
   202→
   203→        # Enable nix-ld for running dynamically linked binaries (CrowdStrike, Kolide, etc.)
   204→        programs.nix-ld.enable = true;
   205→        programs.nix-ld.libraries = with pkgs; [
   206→          # Common libraries needed by security tools
   207→          glibc
   208→          zlib
   209→          openssl
   210→          curl
   211→          libnl
   212→          libgcc
   213→        ];
   214→
   215→        # Nix settings
   216→        nix = {
   217→          settings = {
   218→            experimental-features = [
   219→              "nix-command"
   220→              "flakes"
   221→            ];
   222→            trusted-users = [
   223→              "root"
   224→              username
   225→            ];
   226→          };
   227→          package = pkgs.nixVersions.stable;
   228→        };
   229→
   230→        system.stateVersion = "24.11";
   231→      }
   232→    )
   233→
   234→    # Fonts
   235→    {
   236→      nixpkgs.pkgs = pkgs;
   237→
   238→      fonts.fontconfig.enable = true;
   239→      fonts.packages = with pkgs; [
   240→        inter
   241→        ipaexfont
   242→        ipafont
   243→        joypixels
   244→        nerd-fonts.jetbrains-mono
   245→        noto-fonts-cjk-sans
   246→        noto-fonts-cjk-serif
   247→        noto-fonts-color-emoji
   248→      ];
   249→      fonts.fontconfig.defaultFonts = {
   250→        serif = [
   251→          "Noto Serif CJK JP"
   252→          "DejaVu Serif"
   253→        ];
   254→        sansSerif = [
   255→          "Inter"
   256→          "Noto Sans CJK JP"
   257→          "DejaVu Sans"
   258→        ];
   259→        monospace = [
   260→          "JetBrainsMono Nerd Font"
   261→          "Noto Sans Mono CJK JP"
   262→        ];
   263→        emoji = [
   264→          "JoyPixels"
   265→          "Noto Color Emoji"
   266→        ];
   267→      };
   268→    }
   269→
   270→    # Home Manager integration
   271→    inputs.home-manager.nixosModules.home-manager
   272→    {
   273→      home-manager.backupFileExtension = "hm-backup";
   274→      home-manager.extraSpecialArgs = {
   275→        # Override host detection for matic (isDesktop = true)
   276→        inputs = inputs // {
   277→          host = (import ../../lib/host.nix) // {
   278→            isDesktop = true;
   279→          };
   280→        };
   281→      };
   282→      home-manager.useGlobalPkgs = true;
   283→      home-manager.useUserPackages = true;
   284→      home-manager.users.${username} =
   285→        { config, lib, ... }:
   286→        {
   287→          imports = [
   288→            (import ../../home-manager {
   289→              inherit username;
   290→              # Override host detection for matic (isDesktop = true)
   291→              inputs = inputs // {
   292→                host = (import ../../lib/host.nix) // {
   293→                  isDesktop = true;
   294→                };
   295→              };
   296→              lib = inputs.nixpkgs.lib;
   297→              pkgs = pkgs;
   298→              config = { };
   299→            })
   300→          ];
   301→
   302→          # Animated wallpaper via Wallpaper Engine
   303→          services.linux-wallpaperengine = {
   304→            enable = true;
   305→            assetsPath = "${config.home.homeDirectory}/.local/share/Steam/steamapps/common/wallpaper_engine/assets";
   306→            wallpapers = [
   307→              {
   308→                monitor = "eDP-1";
   309→                wallpaperId = "3602362048";
   310→                scaling = "fill";
   311→                fps = 30;
   312→                audio.silent = true;
   313→              }
   314→            ];
   315→          };
   316→
   317→          # Agenix configuration for GitHub SSH key
   318→          age.identityPaths = [ "/home/${username}/.ssh/id_ed25519" ];
   319→          age.secrets = builtins.mapAttrs (
   320→            name: value:
   321→            {
   322→              file = value.file;
   323→            }
   324→            // (
   325→              if name == "keys/id_github.age" then
   326→                {
   327→                  # Deploy GitHub SSH key to ~/.ssh/ with correct permissions
   328→                  path = "/home/${username}/.ssh/id_ed25519_github";
   329→                  mode = "0600";
   330→                }
   331→              else
   332→                { }
   333→            )
   334→          ) (import ./secrets.nix);
   335→
   336→          # Ensure SSH directory exists before agenix tries to deploy secrets
   337→          home.activation.ensureSshDirectory = config.lib.dag.entryBefore [ "writeBoundary" ] ''
   338→            $DRY_RUN_CMD mkdir -p $VERBOSE_ARG ${config.home.homeDirectory}/.ssh
   339→            $DRY_RUN_CMD chmod $VERBOSE_ARG 700 ${config.home.homeDirectory}/.ssh
   340→          '';
   341→
   342→          # Ensure agenix config directory exists
   343→          home.activation.ensureAgenixDirectory = config.lib.dag.entryBefore [ "writeBoundary" ] ''
   344→            $DRY_RUN_CMD mkdir -p $VERBOSE_ARG ${config.home.homeDirectory}/.config/agenix
   345→            $DRY_RUN_CMD chmod $VERBOSE_ARG 700 ${config.home.homeDirectory}/.config/agenix
   346→          '';
   347→
   348→          # Manually deploy agenix secrets during activation
   349→          # This ensures secrets are deployed even if the agenix activation hook doesn't run properly
   350→          home.activation.deployAgenixSecrets = config.lib.dag.entryAfter [ "writeBoundary" ] ''
   351→            # Decrypt and deploy GitHub SSH key if it doesn't exist
   352→            if [[ ! -f "${config.home.homeDirectory}/.ssh/id_ed25519_github" ]]; then
   353→              echo "Deploying GitHub SSH key from agenix..."
   354→              SECRET_FILE="${builtins.toString ../galactica/keys/id_ed25519.age}"
   355→              if [[ -f "$SECRET_FILE" ]]; then
   356→                $DRY_RUN_CMD ${pkgs.rage}/bin/rage -d -i ${config.home.homeDirectory}/.ssh/id_ed25519 "$SECRET_FILE" -o ${config.home.homeDirectory}/.ssh/id_ed25519_github
   357→                $DRY_RUN_CMD chmod $VERBOSE_ARG 0600 ${config.home.homeDirectory}/.ssh/id_ed25519_github
   358→                echo "✅ GitHub SSH key deployed successfully"
   359→              else
   360→                echo "⚠️  Warning: Secret file not found at $SECRET_FILE"
   361→              fi
   362→            fi
   363→          '';
   364→
   365→          # Import GPG key from agenix (all systems with dotfiles)
   366→          # Fails silently if SSH key isn't authorized to decrypt
   367→          home.activation.importGpgKey = config.lib.dag.entryAfter [ "linkGeneration" ] ''
   368→            $VERBOSE_ECHO "🔑 Starting GPG key import process..."
   369→            GPG_SECRET_FILE="${config.home.homeDirectory}/dotfiles/named-hosts/galactica/keys/gpg.age"
   370→            GPG_TEMP_FILE="${config.home.homeDirectory}/.config/agenix/gpg.key"
   371→
   372→            # Create agenix directory if it doesn't exist
   373→            mkdir -p "${config.home.homeDirectory}/.config/agenix"
   374→
   375→            if [[ -f "$GPG_SECRET_FILE" ]]; then
   376→              # Check if key is already imported
   377→              if ! ${pkgs.gnupg}/bin/gpg --list-secret-keys 2>/dev/null | grep -q "C2E97FCFF482925D"; then
   378→                echo "Importing GPG key from agenix..."
   379→                # Try to decrypt - will fail silently if SSH key isn't authorized
   380→                if ${pkgs.rage}/bin/rage -d -i ${config.home.homeDirectory}/.ssh/id_ed25519 -o "$GPG_TEMP_FILE" "$GPG_SECRET_FILE" 2>/dev/null; then
   381→                  ${pkgs.gnupg}/bin/gpg --batch --import "$GPG_TEMP_FILE" 2>/dev/null
   382→                  rm -f "$GPG_TEMP_FILE"
   383→                  echo "✅ GPG key imported successfully"
   384→                fi
   385→              else
   386→                $VERBOSE_ECHO "ℹ️  GPG key already imported"
   387→              fi
   388→            fi
   389→          '';
   390→
   391→          # GPG configuration for commit signing
   392→          programs.gpg = {
   393→            enable = true;
   394→            settings = {
   395→              default-key = "shunkakinoki@gmail.com";
   396→            };
   397→          };
   398→
